import requests
from urllib.parse import urljoin

# RabbitMQ Management API URL
base_url = 'http://localhost:15672/api/'

# Credentials for admin user
admin_user = 'guest'
admin_password = 'guest'

# Create a session
session = requests.Session()

def login():
    """Login to the RabbitMQ management interface"""
    auth_url = urljoin(base_url, 'users/{}!/login'.format(admin_user))
    response = session.post(auth_url, json={'password': admin_password})
    return response.json()['token']

def create_vhost(vhost_name):
    """Create a new virtual host"""
    token = login()
    headers = {'Authorization': 'Bearer {}'.format(token)}
    vhost_url = urljoin(base_url, 'vhosts')
    data = {'name': vhost_name}
    response = session.post(vhost_url, json=data, headers=headers)
    return response.status_code == 201

def create_user(username):
    """Create a new user"""
    token = login()
    headers = {'Authorization': 'Bearer {}'.format(token)}
    user_url = urljoin(base_url, 'users')
    data = {'username': username}
    response = session.post(user_url, json=data, headers=headers)
    return response.status_code == 201

def grant_permissions(vhost_name, username):
    """Grant permissions for a user in a virtual host"""
    token = login()
    headers = {'Authorization': 'Bearer {}'.format(token)}
    vhost_url = urljoin(base_url, 'vhosts/{}'.format(vhost_name))
    data = {
        'permissions': [
            {'user': username, 'vhost': vhost_name, 'configure': True},
            {'user': username, 'vhost': vhost_name, 'write': True},
            {'user': username, 'vhost': vhost_name, 'read': True}
        ]
    }
    response = session.put(vhost_url, json=data, headers=headers)
    return response.status_code == 200

# Create virtual hosts
vhosts = ['app1', 'app2', 'app3']
for vhost in vhosts:
    create_vhost(vhost)

# Create users and grant permissions
users = ['user1', 'user2', 'user3']
for user in users:
    create_user(user)
    for vhost in vhosts:
        grant_permissions(vhost, user)